@Controller
class SamlController {
    private final SamlService samlService;

    public SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/saml/login")
    public void login(HttpServletResponse response) throws Exception {
        String samlRequest = samlService.createAuthnRequest();
        String redirectUrl = samlService.getIdpSsoUrl() + "?SAMLRequest=" + java.net.URLEncoder.encode(samlRequest, StandardCharsets.UTF_8) + "&RelayState=" + java.net.URLEncoder.encode("/home", StandardCharsets.UTF_8);
        response.sendRedirect(redirectUrl);
    }

    @PostMapping("/saml/acs")
    @ResponseBody
    public String acs(@RequestParam("SAMLResponse") String samlResponse,
                      @RequestParam(value = "RelayState", required = false) String relayState) throws Exception {
        SamlResponseResult result = samlService.processSamlResponse(samlResponse, relayState);
        return "Authenticated user=" + result.getPrincipalName() + " relayState=" + result.getRelayState() + " attrs=" + result.getAttributes();
    }

    @GetMapping(value = "/saml/metadata", produces = "application/xml")
    @ResponseBody
    public String metadata() throws Exception {
        return samlService.getMetadata();
    }
}

