class SelfSignedCertificateGenerator {
    public static X509Certificate generate(String dn, KeyPair keyPair, int days) throws Exception {
        long now = System.currentTimeMillis();
        Date notBefore = new Date(now - 1000L * 60);
        Date notAfter = new Date(now + days * 86400000L);
        byte[] sn = new byte[16];
        new SecureRandom().nextBytes(sn);
        java.math.BigInteger serial = new java.math.BigInteger(1, sn);
        String sigAlg = "SHA256withRSA";
        sun.security.x509.X500Name owner = new sun.security.x509.X500Name(dn);
        sun.security.x509.X509CertInfo info = new sun.security.x509.X509CertInfo();
        info.set(sun.security.x509.X509CertInfo.VERSION, new sun.security.x509.CertificateVersion(sun.security.x509.CertificateVersion.V3));
        info.set(sun.security.x509.X509CertInfo.SERIAL_NUMBER, new sun.security.x509.CertificateSerialNumber(serial));
        info.set(sun.security.x509.X509CertInfo.SUBJECT, owner);
        info.set(sun.security.x509.X509CertInfo.ISSUER, owner);
        info.set(sun.security.x509.X509CertInfo.VALIDITY, new sun.security.x509.CertificateValidity(notBefore, notAfter));
        info.set(sun.security.x509.X509CertInfo.KEY, new sun.security.x509.CertificateX509Key(keyPair.getPublic()));
        info.set(sun.security.x509.X509CertInfo.ALGORITHM_ID, new sun.security.x509.CertificateAlgorithmId(new sun.security.x509.AlgorithmId(java.security.AlgorithmId.get(sigAlg).getOID())));
        sun.security.x509.X509CertImpl cert = new sun.security.x509.X509CertImpl(info);
        cert.sign(keyPair.getPrivate(), sigAlg);
        return cert;
    }
}

